import { workflow, node, trigger, expr, newCredential, placeholder } from '@n8n/workflow-sdk';

const manual_Trigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const run_button_visibility_test = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: { name: 'run button visibility test', parameters: { assignments: { assignments: [{ id: 'status-assignment', name: 'status', value: 'ready', type: 'string' }] }, options: {} } }
});

const run_button_visibility_test_terminal = node({
  type: 'n8n-nodes-base.noOp',
  version: 1,
  config: { name: 'run button visibility test terminal' }
});

const wf = workflow('Ig2u2MoTZJMiSGdd', 'Run Button Visibility Workflow');

export default wf
  .add(manual_Trigger)
  .to(run_button_visibility_test)
  .to(run_button_visibility_test_terminal)
